# solution.py
"""Team Collaboration Manager.

A self-contained, thread-safe, in-memory team collaboration backend.

It manages users, projects, tasks, threaded messaging with attachments,
performance metrics (completion rate, average completion time, peer
ratings) and report generation/export (CSV and PDF).

Design notes
------------
* All entity ids are drawn from a single global counter so that ids are
  unique across *every* entity type.
* A single re-entrant lock is shared by the manager and every sub-store,
  guaranteeing consistent, atomic mutations under concurrent access.
* Every accessor returns deep copies so callers can never mutate internal
  state by holding on to a returned object or list.

Although the originating prompt described a strategy-game ("EmpireForge"),
the accompanying test-suite exercises a team-collaboration domain; this
module implements the behaviour required by those tests.
"""

import copy
import csv
import io
import threading
from collections import defaultdict
from dataclasses import dataclass
from datetime import datetime
from enum import Enum
from typing import List, Optional


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Role a user can hold within the system."""

    MEMBER = "member"
    ADMIN = "admin"
    GUEST = "guest"


class TaskStatus(Enum):
    """Lifecycle status of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of reports that can be produced."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by this module."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an action conflicts with current state."""


# ---------------------------------------------------------------------------
# Domain entities
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A binary attachment associated with a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    """A registered user / team member."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A project owned by a user with a start/end window."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    """A unit of work that belongs to a project."""

    id: int
    project_id: int
    title: str
    description: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Message:
    """A message posted to a project or task, optionally threaded."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment]
    created_at: datetime
    edited_at: Optional[datetime]


@dataclass
class Rating:
    """A peer rating given to a user."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Internal store
# ---------------------------------------------------------------------------
class _Store:
    """A lightweight container holding entities behind a shared lock.

    Every store created by a manager shares the *same* lock object so that
    operations spanning multiple stores remain atomic.
    """

    def __init__(self, lock):
        self._lock = lock
        self.items = {}


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Coordinates all collaboration features behind a single shared lock."""

    def __init__(self, now=None):
        # ``now`` is a zero-argument callable returning the current datetime.
        self._now = now if now is not None else datetime.now

        # One re-entrant lock guards every store and the id counter.
        self._lock = threading.RLock()
        self._id_counter = 0

        # Entity stores -- all share ``self._lock``.
        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Store(self._lock)
        self.reports = _Store(self._lock)

        # Secondary indices for efficient lookups.
        self.tasks.by_project = defaultdict(set)      # project_id -> {task_id}
        self.tasks.by_assignee = defaultdict(set)     # user_id    -> {task_id}
        self.messages.by_project = defaultdict(set)   # project_id -> {msg_id}
        self.messages.by_task = defaultdict(set)       # task_id    -> {msg_id}
        self.performance.by_ratee = defaultdict(set)   # user_id    -> {rating_id}

    # -- internal helpers --------------------------------------------------
    def _next_id(self):
        """Return the next globally-unique id. Caller must hold the lock."""
        self._id_counter += 1
        return self._id_counter

    def _require_user(self, user_id):
        user = self.users.items.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def _require_project(self, project_id):
        project = self.projects.items.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id):
        task = self.tasks.items.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id):
        message = self.messages.items.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message

    @staticmethod
    def _clean_text(value):
        return value.strip() if isinstance(value, str) else value

    # ------------------------------------------------------------------ #
    # User management                                                    #
    # ------------------------------------------------------------------ #
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            uname = self._clean_text(username)
            if not isinstance(uname, str) or not uname:
                raise ValidationError("Username must be a non-empty string")
            mail = self._clean_text(email)
            if not isinstance(mail, str) or not mail or "@" not in mail:
                raise ValidationError("A valid email is required")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            for existing in self.users.items.values():
                if existing.username == uname:
                    raise DuplicateError("Username already in use")
                if existing.email == mail:
                    raise DuplicateError("Email already in use")

            user = User(
                id=self._next_id(),
                username=uname,
                email=mail,
                role=role,
                created_at=self._now(),
            )
            self.users.items[user.id] = user
            return copy.deepcopy(user)

    def get_user(self, user_id):
        with self._lock:
            return copy.deepcopy(self._require_user(user_id))

    def list_users(self):
        with self._lock:
            return [
                copy.deepcopy(self.users.items[uid])
                for uid in sorted(self.users.items)
            ]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self._require_user(user_id)

            if username is not None:
                uname = self._clean_text(username)
                if not isinstance(uname, str) or not uname:
                    raise ValidationError("Username must be a non-empty string")
                for existing in self.users.items.values():
                    if existing.id != user_id and existing.username == uname:
                        raise DuplicateError("Username already in use")
            else:
                uname = None

            if email is not None:
                mail = self._clean_text(email)
                if not isinstance(mail, str) or not mail or "@" not in mail:
                    raise ValidationError("A valid email is required")
                for existing in self.users.items.values():
                    if existing.id != user_id and existing.email == mail:
                        raise DuplicateError("Email already in use")
            else:
                mail = None

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if uname is not None:
                user.username = uname
            if mail is not None:
                user.email = mail
            if role is not None:
                user.role = role
            return copy.deepcopy(user)

    def delete_user(self, user_id):
        with self._lock:
            self._require_user(user_id)

            for project in self.projects.items.values():
                if project.owner_id == user_id:
                    raise ConflictError("User owns a project and cannot be deleted")

            for task_id in self.tasks.by_assignee.get(user_id, set()):
                task = self.tasks.items.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError(
                        "User has open tasks and cannot be deleted"
                    )

            self.users.items.pop(user_id, None)
            self.tasks.by_assignee.pop(user_id, None)
            self.performance.by_ratee.pop(user_id, None)

    # ------------------------------------------------------------------ #
    # Project management                                                 #
    # ------------------------------------------------------------------ #
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            pname = self._clean_text(name)
            if not isinstance(pname, str) or not pname:
                raise ValidationError("Project name must be a non-empty string")
            self._require_user(owner_id)
            if end_date < start_date:
                raise ValidationError("end_date cannot be before start_date")

            project = Project(
                id=self._next_id(),
                name=pname,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self.projects.items[project.id] = project
            return copy.deepcopy(project)

    def get_project(self, project_id):
        with self._lock:
            return copy.deepcopy(self._require_project(project_id))

    def list_projects(self):
        with self._lock:
            return [
                copy.deepcopy(self.projects.items[pid])
                for pid in sorted(self.projects.items)
            ]

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None):
        with self._lock:
            project = self._require_project(project_id)

            if name is not None:
                pname = self._clean_text(name)
                if not isinstance(pname, str) or not pname:
                    raise ValidationError("Project name must be a non-empty string")
            else:
                pname = None

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot be before start_date")

            if pname is not None:
                project.name = pname
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return copy.deepcopy(project)

    def delete_project(self, project_id):
        with self._lock:
            self._require_project(project_id)

            task_ids = list(self.tasks.by_project.get(project_id, set()))
            for task_id in task_ids:
                task = self.tasks.items.pop(task_id, None)
                if task is not None and task.assignee_id is not None:
                    self.tasks.by_assignee[task.assignee_id].discard(task_id)
                for msg_id in list(self.messages.by_task.get(task_id, set())):
                    self.messages.items.pop(msg_id, None)
                self.messages.by_task.pop(task_id, None)
            self.tasks.by_project.pop(project_id, None)

            for msg_id in list(self.messages.by_project.get(project_id, set())):
                self.messages.items.pop(msg_id, None)
            self.messages.by_project.pop(project_id, None)

            self.projects.items.pop(project_id, None)

    # ------------------------------------------------------------------ #
    # Task management                                                    #
    # ------------------------------------------------------------------ #
    def create_task(self, project_id, title, assignee_id=None, deadline=None,
                   description=""):
        with self._lock:
            project = self._require_project(project_id)
            ttitle = self._clean_text(title)
            if not isinstance(ttitle, str) or not ttitle:
                raise ValidationError("Task title must be a non-empty string")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot be before project start")

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=ttitle,
                description=description or "",
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._now(),
            )
            self.tasks.items[task.id] = task
            self.tasks.by_project[project_id].add(task.id)
            if assignee_id is not None:
                self.tasks.by_assignee[assignee_id].add(task.id)
            return copy.deepcopy(task)

    def get_task(self, task_id):
        with self._lock:
            return copy.deepcopy(self._require_task(task_id))

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self.tasks.by_project.get(project_id, set()))
            return [copy.deepcopy(self.tasks.items[tid]) for tid in ids]

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            self._require_user(assignee_id)
            ids = sorted(self.tasks.by_assignee.get(assignee_id, set()))
            return [copy.deepcopy(self.tasks.items[tid]) for tid in ids]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            if task.assignee_id is not None:
                self.tasks.by_assignee[task.assignee_id].discard(task_id)
            task.assignee_id = assignee_id
            self.tasks.by_assignee[assignee_id].add(task_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            if task.assignee_id is not None:
                self.tasks.by_assignee[task.assignee_id].discard(task_id)
            task.assignee_id = new_assignee_id
            self.tasks.by_assignee[new_assignee_id].add(task_id)
            return copy.deepcopy(task)

    def unassign_task(self, task_id):
        with self._lock:
            task = self._require_task(task_id)
            if task.assignee_id is not None:
                self.tasks.by_assignee[task.assignee_id].discard(task_id)
            task.assignee_id = None
            return copy.deepcopy(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects.items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot be before project start")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id, status):
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return copy.deepcopy(task)

    # ------------------------------------------------------------------ #
    # Messaging                                                          #
    # ------------------------------------------------------------------ #
    def post_message(self, author_id, body, project_id=None, task_id=None,
                    parent_id=None, attachments=None):
        with self._lock:
            self._require_user(author_id)

            targets = [t for t in (project_id, task_id) if t is not None]
            if len(targets) != 1:
                raise ValidationError(
                    "Exactly one of project_id or task_id must be supplied"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)

            body_text = body if isinstance(body, str) else ""
            atts = list(attachments) if attachments else []
            if not body_text.strip() and not atts:
                raise ValidationError(
                    "Message must have a body or at least one attachment"
                )

            if parent_id is not None and parent_id not in self.messages.items:
                raise NotFoundError("Parent message {0} not found".format(parent_id))

            now = self._now()
            attachment_objs = [
                Attachment(
                    filename=fname,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=now,
                )
                for (fname, data) in atts
            ]
            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body_text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=now,
                edited_at=None,
            )
            self.messages.items[message.id] = message
            if project_id is not None:
                self.messages.by_project[project_id].add(message.id)
            if task_id is not None:
                self.messages.by_task[task_id].add(message.id)
            return copy.deepcopy(message)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("Only the author may edit a message")
            if not isinstance(new_body, str) or not new_body.strip():
                raise ValidationError("Message body must be a non-empty string")
            message.body = new_body
            message.edited_at = self._now()
            return copy.deepcopy(message)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "Only the author may add an attachment"
                )
            fname = self._clean_text(filename)
            if not isinstance(fname, str) or not fname:
                raise ValidationError("filename must be a non-empty string")
            attachment = Attachment(
                filename=filename,
                size=len(data),
                uploaded_by=uploader_id,
                uploaded_at=self._now(),
            )
            message.attachments.append(attachment)
            return copy.deepcopy(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self.messages.by_project.get(project_id, set()))
            return [copy.deepcopy(self.messages.items[mid]) for mid in ids]

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            ids = sorted(self.messages.by_task.get(task_id, set()))
            return [copy.deepcopy(self.messages.items[mid]) for mid in ids]

    def delete_message(self, message_id, requester_id):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("Only the author may delete a message")
            self.messages.items.pop(message_id, None)
            if message.project_id is not None:
                self.messages.by_project[message.project_id].discard(message_id)
            if message.task_id is not None:
                self.messages.by_task[message.task_id].discard(message_id)

    # ------------------------------------------------------------------ #
    # Performance dashboard                                              #
    # ------------------------------------------------------------------ #
    def _user_tasks(self, user_id):
        ids = self.tasks.by_assignee.get(user_id, set())
        return [self.tasks.items[tid] for tid in ids if tid in self.tasks.items]

    def get_completion_rate(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._user_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._require_user(user_id)
            durations = []
            for task in self._user_tasks(user_id):
                if (task.status == TaskStatus.COMPLETED
                        and task.started_at is not None
                        and task.completed_at is not None):
                    durations.append(
                        (task.completed_at - task.started_at).total_seconds()
                    )
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("A user cannot rate themselves")
            if isinstance(score, bool) or not isinstance(score, int):
                raise ValidationError("score must be an integer 1..5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._require_task(task_id)

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance.items[rating.id] = rating
            self.performance.by_ratee[ratee_id].add(rating.id)
            return copy.deepcopy(rating)

    def _user_ratings(self, user_id):
        ids = self.performance.by_ratee.get(user_id, set())
        return [
            self.performance.items[rid]
            for rid in ids
            if rid in self.performance.items
        ]

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ratings = sorted(self._user_ratings(user_id), key=lambda r: r.id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._user_tasks(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            completion_rate = completed / total if total else 0.0
            avg_time = self.get_average_completion_time(user_id)

            ratings = self._user_ratings(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------ #
    # Reports                                                            #
    # ------------------------------------------------------------------ #
    def _task_stats(self, tasks):
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        in_progress = sum(
            1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
        )
        not_started = sum(
            1 for t in tasks if t.status == TaskStatus.NOT_STARTED
        )
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if (t.status == TaskStatus.COMPLETED
                and t.started_at is not None
                and t.completed_at is not None)
        ]
        avg_time = sum(durations) / len(durations) if durations else None
        return {
            "total_tasks": total,
            "completed_tasks": completed,
            "in_progress_tasks": in_progress,
            "not_started_tasks": not_started,
            "completion_rate": completed / total if total else 0.0,
            "average_completion_time": avg_time,
        }

    def project_progress_report(self, project_id):
        with self._lock:
            self._require_project(project_id)
            now = self._now()
            ids = sorted(self.tasks.by_project.get(project_id, set()))
            tasks = [self.tasks.items[tid] for tid in ids]

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee = {}
            completed = 0
            for task in tasks:
                status_counts[task.status.value] += 1
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
                if (task.deadline is not None
                        and task.status != TaskStatus.COMPLETED
                        and task.deadline < now):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total": 0, "completed": 0},
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1

            total = len(tasks)
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completed / total if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                task_ids = self.tasks.by_project.get(project_id, set())
                tasks = [self.tasks.items[tid] for tid in task_ids]
            else:
                tasks = list(self.tasks.items.values())

            by_user = defaultdict(list)
            for task in tasks:
                if task.assignee_id is not None:
                    by_user[task.assignee_id].append(task)

            rows = []
            for user_id in sorted(by_user):
                user = self.users.items.get(user_id)
                stats = self._task_stats(by_user[user_id])
                ratings = self._user_ratings(user_id)
                rating_count = len(ratings)
                rating_average = (
                    sum(r.score for r in ratings) / rating_count
                    if rating_count
                    else 0.0
                )
                rows.append({
                    "user_id": user_id,
                    "username": user.username if user is not None else "",
                    "total_tasks": stats["total_tasks"],
                    "completed_tasks": stats["completed_tasks"],
                    "completion_rate": stats["completion_rate"],
                    "average_completion_time": stats["average_completion_time"],
                    "rating_count": rating_count,
                    "rating_average": rating_average,
                })

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            user = self._require_user(user_id)
            tasks = sorted(self._user_tasks(user_id), key=lambda t: t.id)
            stats = self._task_stats(tasks)
            ratings = self._user_ratings(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": stats["total_tasks"],
                "completed_tasks": stats["completed_tasks"],
                "in_progress_tasks": stats["in_progress_tasks"],
                "not_started_tasks": stats["not_started_tasks"],
                "completion_rate": stats["completion_rate"],
                "average_completion_time": stats["average_completion_time"],
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": [copy.deepcopy(t) for t in tasks],
            }

    # ------------------------------------------------------------------ #
    # Export                                                             #
    # ------------------------------------------------------------------ #
    def export_report(self, report, fmt):
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict produced by a report method")
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if fmt == ReportFormat.CSV:
            return self._export_csv(report)
        if fmt == ReportFormat.PDF:
            return self._export_pdf(report)
        raise ValidationError("Unsupported report format")

    @staticmethod
    def _stringify(value):
        try:
            return str(value)
        except Exception:  # pragma: no cover - defensive
            return repr(value)

    def _export_csv(self, report):
        out = io.StringIO()
        writer = csv.writer(out)
        rtype = report.get("report_type")

        if rtype == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id", "username", "total_tasks", "completed_tasks",
                "completion_rate", "average_completion_time",
                "rating_count", "rating_average",
            ]
            writer.writerow(header)
            for row in report.get("rows", []):
                writer.writerow([row.get(col, "") for col in header])

        elif rtype == ReportType.INDIVIDUAL_PERFORMANCE.value:
            header = [
                "user_id", "username", "total_tasks", "completed_tasks",
                "in_progress_tasks", "not_started_tasks", "completion_rate",
                "average_completion_time", "rating_count", "rating_average",
            ]
            writer.writerow(header)
            writer.writerow([report.get(col, "") for col in header])

        elif rtype == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(["metric", "value"])
            writer.writerow(["project_id", report.get("project_id", "")])
            writer.writerow(["total_tasks", report.get("total_tasks", "")])
            writer.writerow(
                ["completion_rate", report.get("completion_rate", "")]
            )
            writer.writerow(["overdue_tasks", report.get("overdue_tasks", "")])
            for status_value, count in report.get("status_counts", {}).items():
                writer.writerow(["status:" + str(status_value), count])

        else:
            header = list(report.keys())
            writer.writerow(header)
            writer.writerow([self._stringify(report[col]) for col in header])

        return out.getvalue()

    def _report_to_lines(self, report):
        lines = []
        rtype = report.get("report_type", "report")
        lines.append("Report: {0}".format(rtype))
        if "rows" in report and isinstance(report["rows"], list):
            for row in report["rows"]:
                lines.append(self._stringify(row))
        for key, value in report.items():
            if key in ("report_type", "rows"):
                continue
            lines.append("{0}: {1}".format(key, self._stringify(value)))
        if not lines:
            lines.append("(empty report)")
        return lines

    def _export_pdf(self, report):
        lines = self._report_to_lines(report)
        return self._build_pdf(lines)

    @staticmethod
    def _build_pdf(lines):
        """Build a minimal but structurally valid single-page PDF."""

        def esc(text):
            return (
                text.replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
            )

        content_parts = ["BT", "/F1 12 Tf", "50 750 Td", "14 TL"]
        if lines:
            content_parts.append("({0}) Tj".format(esc(lines[0])))
            for line in lines[1:]:
                content_parts.append("T*")
                content_parts.append("({0}) Tj".format(esc(line)))
        content_parts.append("ET")
        content_stream = "\n".join(content_parts)
        content_bytes = content_stream.encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            (
                b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
                b"/Resources << /Font << /F1 4 0 R >> >> /Contents 5 0 R >>"
            ),
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
            (
                b"<< /Length " + str(len(content_bytes)).encode("ascii")
                + b" >>\nstream\n" + content_bytes + b"\nendstream"
            ),
        ]

        pdf = bytearray()
        pdf += b"%PDF-1.4\n"
        offsets = []
        for index, obj in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += str(index).encode("ascii") + b" 0 obj\n" + obj + b"\nendobj\n"

        xref_pos = len(pdf)
        count = len(objects) + 1
        pdf += b"xref\n"
        pdf += b"0 " + str(count).encode("ascii") + b"\n"
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        pdf += b"trailer\n"
        pdf += b"<< /Size " + str(count).encode("ascii") + b" /Root 1 0 R >>\n"
        pdf += b"startxref\n"
        pdf += str(xref_pos).encode("ascii") + b"\n"
        pdf += b"%%EOF"
        return bytes(pdf)


